// setupPasswordChange.js
import { id } from '../UtilityHtml.js';
import { bindEvent, showPassword } from '../Utility.js';
import { matchInput } from '../general.js';
import { createFormHandler } from './createFormHandler.js';

export const setupPasswordChange = ({
  formId = 'changePassword',
  buttonId = 'button',
  passwordId = 'password',
  confirmId = 'confirm_password',
  showToggleId = 'showPassword',
  errorId = 'confirm_password_error',
  helpId = 'password_help',
  route,
  redirect,
  lengthLimitArray = null,   // { id: [...], max: [...] } or null
  optionalFields = [],
  theme = 'bulma',
  recaptchaAction = 'CHANGE_PASSWORD'
} = {}) => {
  const passwordInput = id(passwordId);
  const showToggle = id(showToggleId);
  const helperText = id(helpId);

  if (passwordInput) {
    passwordInput.setAttribute('autocomplete', 'current-password');
  }

  if (showToggle) {
    showToggle.setAttribute(
      'aria-label',
      'Warning: this will display your password on the screen.'
    );
  }

  if (helperText) {
    helperText.setAttribute('aria-live', 'polite');
    helperText.textContent =
      'Password must be at least 8 characters long, contain at least one uppercase letter, one lowercase letter, one number, and one special character.';
  }

  bindEvent({ id: showToggleId, handler: () => showPassword(passwordId) });
  matchInput(passwordId, confirmId, errorId);

  createFormHandler({
    formId,
    buttonId,
    route,
    redirect,
    theme,
    lengthLimit: lengthLimitArray,
    optionalFields,
    recaptchaAction
  });
};
