// registerHandler.js
import { createFormHandler } from './createFormHandler.js';

export function registerHandler({
  formId,
  buttonId = 'button',
  route,
  redirect,
  theme = 'bootstrap',
  recaptchaAction = 'SUBMIT',
  lengthLimitArray = null,
  optionalFields = []
}) {
  createFormHandler({
    formId,
    buttonId,
    route,
    redirect,
    theme,
    lengthLimit: lengthLimitArray,
    optionalFields,
    recaptchaAction
  });
}
