// processAll.js
'use strict';
import { postFormData } from '../Http.js';
import { showLoader, clearLoader } from '../Loader.js';
import { id } from '../UtilityHtml.js';
import { showError } from '../ShowResponse.js';
import FormHelper from '../FormHelper.js';

/**
 * Handles the submission of a form and redirects the user.
 */
export const loginSubmission = async ({
  formId,
  loginURL,
  redirect,
  css = null,
  lengthLimit = null,      // { id: [...], max: [...] } or null
  optionalFields = [],
  recaptchaToken = null    // { token, action } or null
}) => {
  let loaderClasses = "loader";
  if (css === 'tailwind') {
    loaderClasses = "animate-spin mx-auto block w-10 h-10 border-4 border-blue-600 border-t-transparent rounded-full";
  }

  try {
    const formInput = id(formId);

    if (!formInput) {
      throw new Error(`Form ${formId} not found`);
    }

    const formInputArr = Array.from(formInput.elements);
    const formData = new FormHelper(formInputArr);

    formData.clearError();

    if (lengthLimit) {
      formData.realTimeCheckLen(lengthLimit.id, lengthLimit.max);
    }

    formData.massValidate(optionalFields, { email: 'email', password: 'password' });

    if (formData.result !== 1) {
      const firstError = document.querySelector('[id$="_error"]:not(:empty)');
      if (firstError) {
          firstError.scrollIntoView({ behavior: 'smooth', block: 'center' });
      }
      return;
    }

       const notificationElement = id(`${formId}_notification`) || formInput;
    notificationElement.scrollIntoView({ behavior: 'smooth' });

    showLoader('setLoader', loaderClasses);
    localStorage.setItem('redirect', redirect);

    await postFormData(loginURL, formId, redirect, css, recaptchaToken);

  } catch (err) {
    showError(err);
  } finally {
    clearLoader('setLoader', loaderClasses);
  }
};
